genvar i;
reg [7:0] arr[11:0];
for (i = 0; i < 12; i++) begin
  always_ff @(posedge clk) begin
    arr[i] <= 0;
  end
end

output reg [7:0] out_arr[11:0];
genvar i;
for (i = 0; i < 12; i++) begin
  always_ff @(posedge clk) begin
    out_arr[i] <= 0;
  end
end

reg [7:0] counter[11:0];
output reg [7:0] latched_out[11:0];
genvar i;
for (i = 0; i < 12; i++) begin
  always_ff @(posedge clk) begin
    if (cmd_latch) begin
      latched_out[i] <= counter[i];
      counter[i] <= 0;
    end
  end
end
